mapper.select:
select s.*, c.name categoryName, dp.name diningPointName
from setmeal s
left join category c on s.category_id = c.id
left join dining_point dp on s.dining_point_id = dp.id


        and s.name like concat('%', #{name}, '%')


        and s.status = #{status}


        and s.category_id = #{categoryId}


        and s.dining_point_id = #{diningPointId}


order by s.update_time desc, s.id desc

select * from setmeal


        and name like concat('%', #{name}, '%')


        and category_id = #{categoryId}


        and status = #{status}


        and dining_point_id = #{diningPointId}


order by update_time desc, id desc

select count(id) from setmeal


        and status = #{status}


        and category_id = #{categoryId}
